import axios from 'axios';
import { getUserTokenFromStorage } from '../utils/auth';

const API_URL = '/api/forum';

// Helper function to get auth header
const getAuthConfig = () => {
  const token = getUserTokenFromStorage();
  return {
    headers: {
      Authorization: `Bearer ${token}`
    }
  };
};

// Get all posts with optional filters
const getPosts = async (filters = {}) => {
  try {
    const query = new URLSearchParams();
    
    // Add filters to query
    if (filters.category) query.append('category', filters.category);
    if (filters.search) query.append('search', filters.search);
    if (filters.sortBy) query.append('sortBy', filters.sortBy);
    if (filters.page) query.append('page', filters.page);
    if (filters.limit) query.append('limit', filters.limit);
    
    const queryString = query.toString() ? `?${query.toString()}` : '';
    const response = await axios.get(`${API_URL}/posts${queryString}`);
    return response.data;
  } catch (error) {
    throw error.response?.data?.message || 'Failed to fetch posts';
  }
};

// Get a single post by ID
const getPostById = async (postId) => {
  try {
    const response = await axios.get(`${API_URL}/posts/${postId}`);
    return response.data;
  } catch (error) {
    throw error.response?.data?.message || 'Failed to fetch post';
  }
};

// Create a new post
const createPost = async (postData) => {
  try {
    const response = await axios.post(`${API_URL}/posts`, postData, getAuthConfig());
    return response.data;
  } catch (error) {
    throw error.response?.data?.message || 'Failed to create post';
  }
};

// Update an existing post
const updatePost = async (postId, postData) => {
  try {
    const response = await axios.put(`${API_URL}/posts/${postId}`, postData, getAuthConfig());
    return response.data;
  } catch (error) {
    throw error.response?.data?.message || 'Failed to update post';
  }
};

// Delete a post
const deletePost = async (postId) => {
  try {
    const response = await axios.delete(`${API_URL}/posts/${postId}`, getAuthConfig());
    return response.data;
  } catch (error) {
    throw error.response?.data?.message || 'Failed to delete post';
  }
};

// Get comments for a post
const getComments = async (postId) => {
  try {
    const response = await axios.get(`${API_URL}/posts/${postId}/comments`);
    return response.data;
  } catch (error) {
    throw error.response?.data?.message || 'Failed to fetch comments';
  }
};

// Add a comment to a post
const addComment = async (postId, commentText) => {
  try {
    const response = await axios.post(
      `${API_URL}/posts/${postId}/comments`, 
      { content: commentText }, 
      getAuthConfig()
    );
    return response.data;
  } catch (error) {
    throw error.response?.data?.message || 'Failed to add comment';
  }
};

// Update a comment
const updateComment = async (postId, commentId, commentText) => {
  try {
    const response = await axios.put(
      `${API_URL}/posts/${postId}/comments/${commentId}`, 
      { content: commentText }, 
      getAuthConfig()
    );
    return response.data;
  } catch (error) {
    throw error.response?.data?.message || 'Failed to update comment';
  }
};

// Delete a comment
const deleteComment = async (postId, commentId) => {
  try {
    const response = await axios.delete(
      `${API_URL}/posts/${postId}/comments/${commentId}`, 
      getAuthConfig()
    );
    return response.data;
  } catch (error) {
    throw error.response?.data?.message || 'Failed to delete comment';
  }
};

// Like a post
const likePost = async (postId) => {
  try {
    const response = await axios.post(
      `${API_URL}/posts/${postId}/like`, 
      {}, 
      getAuthConfig()
    );
    return response.data;
  } catch (error) {
    throw error.response?.data?.message || 'Failed to like post';
  }
};

// Unlike a post
const unlikePost = async (postId) => {
  try {
    const response = await axios.delete(
      `${API_URL}/posts/${postId}/like`, 
      getAuthConfig()
    );
    return response.data;
  } catch (error) {
    throw error.response?.data?.message || 'Failed to unlike post';
  }
};

// Bookmark a post
const bookmarkPost = async (postId) => {
  try {
    const response = await axios.post(
      `${API_URL}/posts/${postId}/bookmark`, 
      {}, 
      getAuthConfig()
    );
    return response.data;
  } catch (error) {
    throw error.response?.data?.message || 'Failed to bookmark post';
  }
};

// Remove bookmark from a post
const unbookmarkPost = async (postId) => {
  try {
    const response = await axios.delete(
      `${API_URL}/posts/${postId}/bookmark`, 
      getAuthConfig()
    );
    return response.data;
  } catch (error) {
    throw error.response?.data?.message || 'Failed to remove bookmark';
  }
};

// Get user's bookmarked posts
const getBookmarkedPosts = async () => {
  try {
    const response = await axios.get(
      `${API_URL}/bookmarks`, 
      getAuthConfig()
    );
    return response.data;
  } catch (error) {
    throw error.response?.data?.message || 'Failed to fetch bookmarked posts';
  }
};

// Get user's posts
const getUserPosts = async (userId) => {
  try {
    const response = await axios.get(`${API_URL}/user/${userId}/posts`);
    return response.data;
  } catch (error) {
    throw error.response?.data?.message || 'Failed to fetch user posts';
  }
};

// Get post categories
const getCategories = async () => {
  try {
    const response = await axios.get(`${API_URL}/categories`);
    return response.data;
  } catch (error) {
    throw error.response?.data?.message || 'Failed to fetch categories';
  }
};

// Report a post
const reportPost = async (postId, reason) => {
  try {
    const response = await axios.post(
      `${API_URL}/posts/${postId}/report`, 
      { reason }, 
      getAuthConfig()
    );
    return response.data;
  } catch (error) {
    throw error.response?.data?.message || 'Failed to report post';
  }
};

// Search posts
const searchPosts = async (query) => {
  try {
    const response = await axios.get(`${API_URL}/search?q=${encodeURIComponent(query)}`);
    return response.data;
  } catch (error) {
    throw error.response?.data?.message || 'Failed to search posts';
  }
};

const forumService = {
  getPosts,
  getPostById,
  createPost,
  updatePost,
  deletePost,
  getComments,
  addComment,
  updateComment,
  deleteComment,
  likePost,
  unlikePost,
  bookmarkPost,
  unbookmarkPost,
  getBookmarkedPosts,
  getUserPosts,
  getCategories,
  reportPost,
  searchPosts
};

export default forumService;
